*{box-sizing:border-box} html{scroll-behavior:smooth}
body{margin:0;font-family:Inter,Arial,Helvetica,sans-serif;color:var(--text);background:#fff;line-height:1.65}
a{text-decoration:none;color:inherit}
.wrap{width:min(1220px,calc(100% - 36px));margin:auto}
.section{padding:76px 0}.soft{background:linear-gradient(180deg,#fff,#f7f9fd)}.center{text-align:center}
.eyebrow{display:inline-flex;align-items:center;padding:8px 15px;border-radius:999px;background:rgba(37,99,235,.08);color:#2563eb;font-weight:900;font-size:13px;margin-bottom:16px}
.eyebrow.dark{background:rgba(255,255,255,.11);border:1px solid rgba(255,255,255,.16);color:#fff}
.title{margin:0 0 16px;font-size:clamp(32px,4vw,58px);line-height:1.05;color:var(--ink);letter-spacing:-1.5px}
.sub{max-width:890px;margin:0 auto 34px;color:var(--muted);font-size:17px}
.btns{display:flex;flex-wrap:wrap;gap:13px;margin-top:26px}.btns.center{justify-content:center}
.btn{display:inline-flex;align-items:center;justify-content:center;padding:14px 22px;border-radius:999px;font-weight:900;border:1px solid transparent;transition:.25s}
.btn:hover{transform:translateY(-3px)} .btn-main{background:var(--grad);color:#fff;box-shadow:0 16px 32px rgba(37,99,235,.24)}
.btn-outline{background:rgba(255,255,255,.08);color:#fff;border-color:rgba(255,255,255,.22)} .btn-light{background:#fff;color:var(--ink);border-color:var(--line);box-shadow:0 10px 22px rgba(7,17,31,.06)}
.nav{position:absolute;left:0;right:0;top:0;z-index:10;padding:18px 0}
.nav-inner{display:flex;align-items:center;justify-content:space-between;padding:9px 12px;border:1px solid rgba(255,255,255,.12);border-radius:999px;background:rgba(255,255,255,.06);backdrop-filter:blur(16px)}
.logo-wrap{display:flex;align-items:center;gap:12px;color:#fff;font-weight:900}.logo-wrap img{height:40px;max-width:175px;object-fit:contain;background:#fff;border-radius:10px;padding:5px}
.nav-links{display:flex;gap:8px;flex-wrap:wrap}.nav-links a{padding:9px 13px;border-radius:999px;background:rgba(255,255,255,.08);border:1px solid rgba(255,255,255,.11);color:rgba(255,255,255,.84);font-size:13px;font-weight:900}

.hero{position:relative;overflow:hidden;padding:124px 0 82px;background:radial-gradient(circle at 10% 10%,rgba(22,199,132,.25),transparent 28%),radial-gradient(circle at 88% 6%,rgba(37,99,235,.32),transparent 32%),radial-gradient(circle at 55% 110%,rgba(124,58,237,.22),transparent 40%),linear-gradient(180deg,#050914,#07111f 48%,#0d1b2f);color:#fff}
.hero:before{content:"";position:absolute;inset:0;background-image:linear-gradient(rgba(255,255,255,.035) 1px,transparent 1px),linear-gradient(90deg,rgba(255,255,255,.035) 1px,transparent 1px);background-size:42px 42px}
.hero:after{content:"";position:absolute;left:-10%;right:-10%;bottom:-1px;height:72px;background:linear-gradient(180deg,transparent,#fff)}
.hero-grid{position:relative;z-index:2;display:grid;grid-template-columns:1.02fr .98fr;gap:42px;align-items:center}
