.hero-tags{display:flex;flex-wrap:wrap;gap:9px;margin-top:22px}.hero-tags span{padding:9px 13px;border-radius:999px;background:rgba(255,255,255,.09);border:1px solid rgba(255,255,255,.12);font-weight:900;font-size:13px;color:rgba(255,255,255,.88)}
.hero-trust-row{display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin-top:24px}
