.hero-trust-row b{display:block;color:#fff;font-size:17px;margin-bottom:3px}.hero-trust-row span{display:block;color:rgba(255,255,255,.66);font-size:12px;line-height:1.45}

.snapshot{border-radius:34px;padding:18px;background:linear-gradient(180deg,rgba(255,255,255,.15),rgba(255,255,255,.08));border:1px solid rgba(255,255,255,.18);box-shadow:0 30px 80px rgba(0,0,0,.34);backdrop-filter:blur(20px)}
.snapshot-top{display:flex;justify-content:space-between;align-items:center;color:rgba(255,255,255,.82);font-weight:900;margin-bottom:14px}.snapshot-top small{padding:7px 11px;border-radius:999px;background:rgba(255,255,255,.10)}
.snapshot-main{background:#fff;color:var(--ink);border-radius:28px;padding:25px;position:relative;overflow:hidden}.snapshot-main:after{content:"";position:absolute;right:-55px;top:-55px;width:160px;height:160px;border-radius:50%;background:rgba(37,99,235,.08)}
