.profile-card{border-radius:32px;padding:30px;background:radial-gradient(circle at 10% 10%,rgba(22,199,132,.09),transparent 34%),radial-gradient(circle at 100% 0%,rgba(37,99,235,.08),transparent 30%),#fff}
