.company-proof-strip{display:grid;grid-template-columns:repeat(4,1fr);gap:14px;margin-top:20px}.company-proof{padding:18px;border-radius:24px;background:#fff;border:1px solid var(--line);box-shadow:0 12px 28px rgba(7,17,31,.055)}
