/* improved trust section */
.trust-pro{background:radial-gradient(circle at 16% 0%,rgba(22,199,132,.18),transparent 30%),radial-gradient(circle at 88% 10%,rgba(37,99,235,.18),transparent 28%),linear-gradient(135deg,#07111f,#0d1b2f);color:#fff}
.trust-pro .title{color:#fff}.trust-pro .sub{color:rgba(255,255,255,.72)}
