.trust-grid-pro{display:grid;grid-template-columns:1fr 1fr;gap:14px}
.trust-card-pro{padding:22px;border-radius:26px;background:#fff;color:var(--ink);box-shadow:0 12px 32px rgba(0,0,0,.12)}
