.why-grid{display:grid;grid-template-columns:repeat(5,1fr);gap:14px}
.why-card{position:relative;overflow:hidden;background:#fff;border:1px solid var(--line);border-radius:24px;padding:20px;box-shadow:0 12px 30px rgba(7,17,31,.055);text-align:left;min-height:198px}.why-card:before{content:"";position:absolute;inset:0 0 auto;height:4px;background:var(--grad)}
.why-no{display:inline-grid;place-items:center;width:40px;height:40px;border-radius:15px;background:rgba(37,99,235,.10);color:#2563eb;font-weight:900;margin-bottom:12px}.why-card h3{margin:0 0 6px;color:var(--ink);font-size:17px;line-height:1.2}.why-card p{margin:0;color:var(--muted);font-size:13px;line-height:1.52}
.vm-intro{max-width:960px;margin:0 auto 26px;padding:19px;border-radius:24px;background:linear-gradient(135deg,rgba(37,99,235,.08),rgba(22,199,132,.07));border:1px solid rgba(37,99,235,.14);text-align:left;color:var(--muted);font-size:15px}.vm-intro strong{color:var(--ink)}
.vision-mission{display:grid;grid-template-columns:1fr 1fr;gap:20px}.vm-card{position:relative;overflow:hidden;border-radius:30px;padding:28px;background:#fff;border:1px solid var(--line);box-shadow:var(--shadow)}.vm-card:before{content:"";position:absolute;inset:0 0 auto;height:5px;background:var(--grad)}.vm-card h3{font-size:30px;line-height:1.1;margin:0 0 10px;color:var(--ink)}.vm-card p{margin:0;color:var(--muted);font-size:16px}.vm-card.darkbox{background:var(--ink);color:#fff}.vm-card.darkbox h3{color:#fff}.vm-card.darkbox p{color:rgba(255,255,255,.76)}
.value-strip{display:grid;grid-template-columns:repeat(4,1fr);gap:14px;margin-top:20px}.value-strip div{padding:17px;border-radius:22px;background:#fff;border:1px solid var(--line);box-shadow:0 12px 28px rgba(7,17,31,.055)}.value-strip b{display:block;color:var(--ink);margin-bottom:4px}.value-strip span{display:block;color:var(--muted);font-size:13px}

.process-showcase{display:grid;grid-template-columns:.9fr 1.1fr;gap:24px;align-items:stretch}.process-visual{position:relative;overflow:hidden;border-radius:32px;background:linear-gradient(135deg,#07111f,#0d1b2f);color:#fff;padding:30px;box-shadow:var(--shadow)}.process-visual:before{content:"";position:absolute;right:-80px;top:-80px;width:220px;height:220px;border-radius:50%;background:rgba(37,99,235,.22)}.process-visual h3{position:relative;color:#fff;font-size:32px;line-height:1.08;margin:0 0 12px}.process-visual p{position:relative;color:rgba(255,255,255,.72);margin:0}.process-pills{position:relative;display:grid;gap:10px;margin-top:22px}.process-pills span{padding:13px 15px;border-radius:18px;background:rgba(255,255,255,.08);border:1px solid rgba(255,255,255,.12);font-weight:900}
.timeline{display:grid;gap:12px}.step{display:grid;grid-template-columns:66px 1fr;gap:16px;padding:18px;border-radius:24px;background:#fff;border:1px solid var(--line);box-shadow:0 10px 24px rgba(7,17,31,.055);transition:.25s}.step:hover{transform:translateX(5px);box-shadow:var(--shadow)}.step-num{width:58px;height:58px;border-radius:20px;background:var(--grad);display:grid;place-items:center;color:#fff;font-weight:900;font-size:20px}.step h3{margin:0 0 4px;color:var(--ink)}.step p{margin:0;color:var(--muted);font-size:14px}
.cta{position:relative;overflow:hidden;padding:90px 0;background:linear-gradient(135deg,#07111f,#0d1b2f);color:#fff;text-align:center}.cta:before{content:"";position:absolute;inset:0;background:radial-gradient(circle at 20% 0%,rgba(22,199,132,.18),transparent 32%),radial-gradient(circle at 80% 20%,rgba(37,99,235,.20),transparent 32%)}.cta .wrap{position:relative;z-index:2}.cta h2{margin:0 auto 18px;max-width:950px;font-size:clamp(34px,4.4vw,60px);line-height:1.05}.cta p{max-width:850px;margin:auto;color:rgba(255,255,255,.72);font-size:18px}.contact{margin-top:18px;font-weight:900;color:#dbeafe}
@media(max-width:1040px){
  .hero-grid,.credentials-layout,.grid-2,.process-showcase,.solutions-shell,.trust-shell{grid-template-columns:1fr}
  .grid-4,.trust-grid,.company-proof-strip,.value-strip,.trust-proof-row{grid-template-columns:repeat(2,1fr)}
  .grid-3,.vision-mission{grid-template-columns:1fr}
  .why-grid{grid-template-columns:repeat(2,1fr)}
