}
@media(max-width:690px){
  .section{padding:58px 0}.hero{padding-top:112px;padding-bottom:64px}.hero h1{letter-spacing:-1.2px}
  .hero-trust-row,.grid-4,.trust-grid,.company-proof-strip,.value-strip,.why-grid,.cred-list,.bpo-points,.snapshot-grid,.media-collage,.group-gallery,.solutions-points,.trust-grid-pro,.trust-proof-row{grid-template-columns:1fr}
  .media-card.large{grid-row:auto}.media-collage{grid-template-rows:auto}.media-card{height:245px}.btn{width:100%}.step{grid-template-columns:1fr}.logo-wrap span{display:none}.nav-inner{border-radius:24px}
}

