.executive-card h3{
  margin:0 0 10px;
  color:var(--ink);
  font-size:28px;
  line-height:1.12;
  letter-spacing:-.5px;
}
.executive-card.dark-card h3{color:#fff}
.executive-card p{
  margin:0;
  color:var(--muted);
  font-size:16px;
}
.executive-card.dark-card p{color:rgba(255,255,255,.74)}
.executive-mini{
  display:grid;
  grid-template-columns:repeat(3,1fr);
  gap:12px;
  margin-top:18px;
}
.executive-mini div{
  padding:14px;
  border-radius:18px;
  background:#f8fafc;
  border:1px solid var(--line);
}
.executive-card.dark-card .executive-mini div{
  background:rgba(255,255,255,.08);
  border-color:rgba(255,255,255,.12);
}
.executive-mini b{
  display:block;
  color:var(--ink);
  font-size:14px;
  margin-bottom:3px;
}
.executive-card.dark-card .executive-mini b{color:#fff}
.executive-mini span{
  display:block;
  color:var(--muted);
  font-size:12px;
  line-height:1.4;
}
.executive-card.dark-card .executive-mini span{color:rgba(255,255,255,.68)}
.trust-strip{
  margin-top:26px;
}
.trust-strip .card{
  background:linear-gradient(180deg,#fff,#fbfcff);
}
.profile-card,
.bpo-card,
.credentials-content,
.solutions-intro,
.process-visual,
.vm-card,
.service-card,
.card{
  border-radius:32px;
}
.bpo-card{
  display:grid;
  grid-template-rows:250px auto;
}
.credentials-section{
  background:
    radial-gradient(circle at 12% 8%, rgba(37,99,235,.07), transparent 30%),
    linear-gradient(180deg,#fff,#f7f9fd);
}
.media-collage{
  grid-template-rows:220px 220px;
}
.solutions-shell{
  padding:22px;
  border-radius:38px;
  background:#fff;
  border:1px solid var(--line);
  box-shadow:var(--shadow);
}
.solutions-intro{
  box-shadow:none;
  border-color:rgba(231,235,243,.7);
}
.group-gallery .group-shot{
  height:220px;
}
.grid-3 .service-card{
  background:linear-gradient(180deg,#fff,#fbfcff);
}
.trust-pro{
  position:relative;
  overflow:hidden;
}
.trust-pro:before{
  content:"";
  position:absolute;
  inset:0;
  background-image:
    linear-gradient(rgba(255,255,255,.035) 1px, transparent 1px),
    linear-gradient(90deg,rgba(255,255,255,.035) 1px, transparent 1px);
  background-size:44px 44px;
}
.trust-pro .wrap{position:relative;z-index:2}
.why-card{
  min-height:210px;
  background:linear-gradient(180deg,#fff,#fbfcff);
}
.vision-mission{
  align-items:stretch;
}
.vm-card{
  min-height:250px;
}
.value-strip div{
  background:linear-gradient(180deg,#fff,#fbfcff);
}
.process-showcase{
  padding:22px;
  border-radius:38px;
  background:linear-gradient(180deg,#fff,#f8fafc);
  border:1px solid var(--line);
  box-shadow:var(--shadow);
}
.timeline .step{
  background:#fff;
}
.final-proof-section{
  padding:80px 0;
  background:#fff;
}
.final-proof-layout{
  display:grid;
  grid-template-columns:.8fr 1.2fr;
  gap:28px;
  align-items:center;
}
.final-proof-intro{
  padding:34px;
  border-radius:36px;
  background:linear-gradient(135deg,#07111f,#0d1b2f);
  color:#fff;
  box-shadow:var(--shadow);
}
.final-proof-intro h2{
  margin:0 0 12px;
  font-size:clamp(30px,3.4vw,50px);
  line-height:1.08;
  color:#fff;
}
.final-proof-intro p{
  color:rgba(255,255,255,.72);
  margin:0;
}
.final-proof-grid{
  display:grid;
  grid-template-columns:repeat(2,1fr);
  gap:14px;
}
.final-proof-card{
  padding:22px;
  border-radius:26px;
  background:#fff;
  border:1px solid var(--line);
  box-shadow:0 14px 34px rgba(7,17,31,.07);
}
.final-proof-card b{
  display:block;
  color:var(--ink);
  font-size:18px;
  margin-bottom:6px;
}
.final-proof-card span{
  display:block;
  color:var(--muted);
  font-size:14px;
  line-height:1.55;
}
.cta{
  padding:96px 0;
}
@media(max-width:1040px){
  .executive-grid,.final-proof-layout{grid-template-columns:1fr}
}
@media(max-width:690px){
  .section{padding:62px 0}
  .executive-mini,.final-proof-grid{grid-template-columns:1fr}
  .solutions-shell,.process-showcase{padding:14px}
}


/* ===== Final Hero + Service Cards Update ===== */
.hero-grid{
  grid-template-columns:1fr 1fr;
  align-items:center;
}
.snapshot{
  max-width:620px;
  margin-left:auto;
  padding:18px;
}
.snapshot-main{
  min-height:215px;
  display:flex;
  flex-direction:column;
  justify-content:center;
}
.snapshot-grid{
  margin-top:14px;
}
.hero-trust-under-snapshot{
  margin-top:14px;
  display:grid;
  grid-template-columns:repeat(3,1fr);
  gap:12px;
}
.hero-trust-under-snapshot div{
  position:relative;
  overflow:hidden;
  padding:17px 14px;
  border-radius:22px;
  background:linear-gradient(180deg,rgba(255,255,255,.18),rgba(255,255,255,.08));
  border:1px solid rgba(255,255,255,.16);
  box-shadow:0 18px 34px rgba(0,0,0,.15);
}
.hero-trust-under-snapshot div:before{
  content:"";
  position:absolute;
  inset:0 0 auto;
  height:3px;
  background:linear-gradient(90deg,#16c784,#2563eb,#7c3aed);
}
.hero-trust-under-snapshot b{
  display:block;
  color:#fff;
  font-size:15px;
  line-height:1.2;
  margin:0 0 5px;
}
.hero-trust-under-snapshot span{
  display:block;
  color:rgba(255,255,255,.72);
  font-size:11.5px;
  line-height:1.42;
}
.hero .btns{
  margin-bottom:0;
}
.hero-tags{
  max-width:760px;
}
.service-card{
  background:
    radial-gradient(circle at 100% 0%, rgba(37,99,235,.065), transparent 34%),
    linear-gradient(180deg,#fff,#fbfcff);
  border:1px solid rgba(231,235,243,.95);
  box-shadow:0 18px 45px rgba(7,17,31,.075);
  padding:28px;
  min-height:285px;
}
.service-card:before{
  height:6px;
  background:linear-gradient(90deg,#16c784,#2563eb,#7c3aed);
}
.service-card .icon{
  width:56px;
  height:56px;
  border-radius:20px;
  font-size:26px;
  background:
    radial-gradient(circle at 25% 15%,rgba(255,255,255,.6),transparent 35%),
    linear-gradient(135deg,rgba(22,199,132,.12),rgba(37,99,235,.10),rgba(124,58,237,.10));
  box-shadow:inset 0 0 0 1px rgba(37,99,235,.08);
}
.service-card h3{
  font-size:23px;
  line-height:1.2;
  letter-spacing:-.3px;
  margin-bottom:10px;
}
.service-card p{
  font-size:15px;
  line-height:1.62;
}
.service-card ul{
  margin-top:18px;
  padding-top:16px;
  border-top:1px solid var(--line);
}
.service-card li{
  display:flex;
  align-items:flex-start;
  gap:8px;
  font-size:14px;
}
.service-card li:before{
  content:"✓";
  flex:0 0 22px;
  width:22px;
  height:22px;
  display:inline-grid;
  place-items:center;
  border-radius:50%;
  background:rgba(37,99,235,.10);
  color:#2563eb;
