  font-size:12px;
}
.solutions-shell{
  margin-bottom:30px;
}
@media(max-width:1040px){
  .hero-grid{grid-template-columns:1fr}
  .snapshot{max-width:100%;margin-left:0}
}
@media(max-width:690px){
  .hero-trust-under-snapshot{grid-template-columns:1fr}
  .snapshot-main{min-height:auto}
  .service-card{min-height:auto;padding:24px}
}


/* ===== Premium Cards Upgrade V7: Bento + Glass + Growth System ===== */
.snapshot{
  position:relative;
  overflow:hidden;
}
.snapshot:before{
  content:"";
  position:absolute;
  inset:-1px;
  border-radius:34px;
  padding:1px;
  background:linear-gradient(135deg,rgba(22,199,132,.42),rgba(37,99,235,.42),rgba(124,58,237,.42));
  -webkit-mask:linear-gradient(#000 0 0) content-box,linear-gradient(#000 0 0);
  -webkit-mask-composite:xor;
          mask-composite:exclude;
  pointer-events:none;
}
.snapshot-main{
  background:
    radial-gradient(circle at 12% 0%,rgba(22,199,132,.08),transparent 35%),
    radial-gradient(circle at 100% 10%,rgba(124,58,237,.10),transparent 35%),
    rgba(255,255,255,.96);
}
.snapshot-grid div{
  background:rgba(255,255,255,.94);
  border:1px solid rgba(255,255,255,.42);
  box-shadow:0 12px 25px rgba(7,17,31,.08);
}
.premium-proof-cards{
  grid-template-columns:repeat(3,1fr);
  gap:12px;
  margin-top:15px;
}
.premium-proof-cards .proof-card-hero{
  position:relative;
  min-height:152px;
  padding:17px 15px 16px;
  border-radius:24px;
  background:
    linear-gradient(180deg,rgba(255,255,255,.18),rgba(255,255,255,.075)),
    radial-gradient(circle at 20% 0%,rgba(22,199,132,.18),transparent 40%);
  border:1px solid rgba(255,255,255,.18);
  box-shadow:0 20px 42px rgba(0,0,0,.18), inset 0 1px 0 rgba(255,255,255,.14);
  backdrop-filter:blur(14px);
  isolation:isolate;
  transition:.25s;
}
.premium-proof-cards .proof-card-hero:hover{
  transform:translateY(-4px);
  background:
    linear-gradient(180deg,rgba(255,255,255,.22),rgba(255,255,255,.09)),
    radial-gradient(circle at 20% 0%,rgba(37,99,235,.20),transparent 42%);
}
.premium-proof-cards .proof-card-hero:before{
  content:"";
  position:absolute;
  inset:0 0 auto;
  height:4px;
  background:linear-gradient(90deg,#16c784,#2563eb,#7c3aed);
  border-radius:24px 24px 0 0;
}
.premium-proof-cards .proof-card-hero:after{
  content:"";
  position:absolute;
  right:-24px;
  bottom:-24px;
  width:92px;
  height:92px;
  border-radius:50%;
  background:rgba(255,255,255,.07);
  z-index:-1;
}
.proof-icon{
  display:grid !important;
  place-items:center;
  width:42px;
  height:42px;
  border-radius:16px;
  background:rgba(255,255,255,.14);
  border:1px solid rgba(255,255,255,.16);
  margin-bottom:11px;
  font-size:20px !important;
  color:#fff !important;
}
.proof-card-hero small{
  display:block;
  color:rgba(255,255,255,.58);
  font-weight:900;
  font-size:10.5px;
  text-transform:uppercase;
  letter-spacing:.9px;
  margin-bottom:4px;
}
.proof-card-hero b{
  color:#fff;
  font-size:17px;
  line-height:1.15;
  margin-bottom:7px;
}
.proof-card-hero span:not(.proof-icon){
  color:rgba(255,255,255,.72);
  font-size:12px;
  line-height:1.45;
}

/* Service card modern market presentation */
.grid-3{
  align-items:stretch;
}
.service-card{
  position:relative;
  isolation:isolate;
  padding:30px;
  border-radius:34px;
  min-height:310px;
  background:
    radial-gradient(circle at 88% 0%,rgba(37,99,235,.10),transparent 35%),
    linear-gradient(180deg,#ffffff,#f9fbff);
  border:1px solid rgba(226,232,240,.95);
  box-shadow:0 20px 50px rgba(7,17,31,.08);
  overflow:hidden;
}
.service-card:before{
  height:0;
}
.service-card:after{
  content:"";
  position:absolute;
  inset:0;
  border-radius:34px;
  padding:1.5px;
  background:linear-gradient(135deg,rgba(22,199,132,.45),rgba(37,99,235,.42),rgba(124,58,237,.38));
  -webkit-mask:linear-gradient(#000 0 0) content-box,linear-gradient(#000 0 0);
  -webkit-mask-composite:xor;
          mask-composite:exclude;
  opacity:.65;
  pointer-events:none;
}
.service-card:hover{
  transform:translateY(-7px);
  box-shadow:0 28px 70px rgba(7,17,31,.14);
}
.service-card .icon{
  position:relative;
  width:60px;
  height:60px;
  border-radius:22px;
  font-size:27px;
  margin-bottom:18px;
  background:
    radial-gradient(circle at 30% 20%,rgba(255,255,255,.95),transparent 38%),
    linear-gradient(135deg,rgba(22,199,132,.18),rgba(37,99,235,.14),rgba(124,58,237,.14));
  box-shadow:0 12px 28px rgba(37,99,235,.12), inset 0 0 0 1px rgba(37,99,235,.10);
}
.service-card .icon:after{
  content:"";
  position:absolute;
  width:22px;
  height:22px;
  right:-5px;
  bottom:-5px;
  border-radius:10px;
  background:linear-gradient(135deg,#16c784,#2563eb);
  opacity:.95;
  box-shadow:0 10px 22px rgba(37,99,235,.22);
}
.service-card h3{
  font-size:24px;
  line-height:1.14;
  letter-spacing:-.45px;
  margin-bottom:12px;
}
.service-card p{
  font-size:15.5px;
  line-height:1.62;
  color:#667085;
}
.service-card ul{
  margin-top:20px;
  padding-top:18px;
  border-top:1px dashed rgba(102,112,133,.24);
  gap:10px;
}
.service-card li{
  color:#475467;
  font-weight:700;
}
.service-card li:before{
  background:linear-gradient(135deg,rgba(22,199,132,.14),rgba(37,99,235,.12));
  color:#2563eb;
  box-shadow:inset 0 0 0 1px rgba(37,99,235,.08);
}
.service-card:nth-child(1){background:radial-gradient(circle at 88% 0%,rgba(22,199,132,.12),transparent 35%),linear-gradient(180deg,#fff,#f9fbff)}
.service-card:nth-child(2){background:radial-gradient(circle at 88% 0%,rgba(37,99,235,.12),transparent 35%),linear-gradient(180deg,#fff,#f9fbff)}
.service-card:nth-child(3){background:radial-gradient(circle at 88% 0%,rgba(124,58,237,.12),transparent 35%),linear-gradient(180deg,#fff,#f9fbff)}
.service-card:nth-child(4){background:radial-gradient(circle at 88% 0%,rgba(249,115,22,.10),transparent 35%),linear-gradient(180deg,#fff,#f9fbff)}
.service-card:nth-child(5){background:radial-gradient(circle at 88% 0%,rgba(16,185,129,.12),transparent 35%),linear-gradient(180deg,#fff,#f9fbff)}
.service-card:nth-child(6){background:radial-gradient(circle at 88% 0%,rgba(14,165,233,.12),transparent 35%),linear-gradient(180deg,#fff,#f9fbff)}
.solutions-shell{
  background:
    radial-gradient(circle at 0% 0%,rgba(37,99,235,.06),transparent 30%),
    #fff;
}
@media(max-width:1040px){
  .premium-proof-cards{grid-template-columns:repeat(3,1fr)}
}
@media(max-width:760px){
  .premium-proof-cards{grid-template-columns:1fr}
  .premium-proof-cards .proof-card-hero{min-height:auto}
  .service-card{min-height:auto}
}


/* ===== GrowBoostly Website Theme Match Final V8 =====
   Goal: match GrowBoostly website style — light premium sections, growth-system palette,
   green/blue/violet gradients, clean cards, not like a pasted separate page.
*/
:root{
  --gb-green:#16c784;
  --gb-blue:#2563eb;
  --gb-violet:#7c3aed;
  --gb-ink:#07111f;
  --gb-text:#172033;
  --gb-muted:#667085;
  --gb-line:#e7ebf3;
  --gb-soft:#f7f9fd;
  --gb-grad:linear-gradient(135deg,#16c784 0%,#2563eb 55%,#7c3aed 100%);
}
body{
  background:#ffffff !important;
  color:var(--gb-text);
}
.wrap{
  width:min(1180px,calc(100% - 36px));
}
.section{
  padding:82px 0;
}
.eyebrow{
  background:rgba(37,99,235,.075) !important;
  color:#2563eb !important;
  border:1px solid rgba(37,99,235,.10);
  box-shadow:none;
}
.eyebrow.dark{
  background:rgba(255,255,255,.10) !important;
  color:#fff !important;
  border-color:rgba(255,255,255,.16);
}

/* Header more like existing clean website, not over-glassy */
.nav{
  padding:18px 0;
}
.nav-inner{
  background:rgba(7,17,31,.52);
  border:1px solid rgba(255,255,255,.13);
  box-shadow:0 18px 50px rgba(7,17,31,.22);
}
.nav-links a{
  background:rgba(255,255,255,.075);
  border-color:rgba(255,255,255,.12);
}
.nav-links a:hover{
  background:rgba(255,255,255,.16);
}

/* Hero: Clean Light Gradient style with premium dark text contrast */
.hero{
  padding:130px 0 82px !important;
  background:
    radial-gradient(circle at 8% 10%,rgba(22,199,132,.08),transparent 30%),
    radial-gradient(circle at 90% 5%,rgba(37,99,235,.09),transparent 32%),
    radial-gradient(circle at 52% 110%,rgba(124,58,237,.08),transparent 42%),
    linear-gradient(180deg,#f7f9fd 0%,#ffffff 100%) !important;
  color: var(--gb-text) !important;
}
.hero:before{
  content:"";
  position:absolute;
  inset:0;
  background-image:
    linear-gradient(rgba(7,17,31,.03) 1px, transparent 1px),
    linear-gradient(90deg, rgba(7,17,31,.03) 1px, transparent 1px) !important;
  background-size:42px 42px !important;
}
.hero:after{
  height:68px !important;
}
.hero-grid{
  grid-template-columns:1.02fr .98fr !important;
  gap:46px !important;
}
.hero h1{
  font-size:clamp(42px,5vw,66px) !important;
  line-height:1 !important;
  letter-spacing:-2.2px !important;
  color: var(--gb-ink) !important;
}
.hero p{
  font-size:18px !important;
  line-height:1.72;
  color: var(--gb-muted) !important;
}
.hero .accent{
  background: var(--gb-grad) !important;
  -webkit-background-clip: text !important;
  -webkit-text-fill-color: transparent !important;
  color: transparent !important;
}
.hero .eyebrow, .hero .eyebrow.dark{
  background: rgba(37,99,235,.075) !important;
  color: #2563eb !important;
  border: 1px solid rgba(37,99,235,.10) !important;
}
.hero .btn-outline{
  background: rgba(7,17,31,.04) !important;
  color: var(--gb-text) !important;
  border: 1px solid var(--gb-line) !important;
}
.hero .btn-outline:hover{
  background: rgba(7,17,31,.08) !important;
  color: var(--gb-ink) !important;
}

/* Snapshot right-side composition */
.snapshot{
  max-width:620px;
  margin-left:auto;
  border-radius:34px !important;
  padding:18px !important;
  background:
    radial-gradient(circle at 12% 0%, rgba(22,199,132,.14), transparent 32%),
    radial-gradient(circle at 88% 8%, rgba(37,99,235,.18), transparent 34%),
    linear-gradient(145deg, #07111f 0%, #0d1b2f 52%, #111827 100%) !important;
  border: 1px solid rgba(255,255,255,0.10) !important;
  box-shadow: 0 30px 70px rgba(7,17,31,0.28) !important;
  backdrop-filter: blur(14px) !important;
}
.hero .snapshot-top{
  color: #ffffff !important;
}
.hero .snapshot-top small{
  background: rgba(255,255,255,0.10) !important;
  color: rgba(255,255,255,0.78) !important;
  border: 1px solid rgba(255,255,255,0.08) !important;
}
.snapshot-main{
  min-height:210px;
  border-radius:28px !important;
  background:
    radial-gradient(circle at 12% 0%, rgba(22,199,132,.10), transparent 35%),
    radial-gradient(circle at 100% 10%, rgba(37,99,235,.08), transparent 35%),
    #ffffff !important;
}
.snapshot-grid{
  grid-template-columns:1fr 1fr !important;
  gap:12px !important;
  margin-top:13px !important;
}
.snapshot-grid div{
  border-radius:19px !important;
  padding:14px !important;
}
.premium-proof-cards{
  grid-template-columns:repeat(3,1fr) !important;
  gap:12px !important;
  margin-top:13px !important;
}
.premium-proof-cards .proof-card-hero{
  min-height:148px !important;
  border-radius:22px !important;
  padding:16px 13px !important;
  background:
    linear-gradient(180deg, rgba(255,255,255,0.95), rgba(255,255,255,0.75)),
    radial-gradient(circle at 20% 0%, rgba(22,199,132,0.08), transparent 40%) !important;
  border: 1px solid rgba(231, 235, 243, 0.9) !important;
  box-shadow: 0 12px 28px rgba(7,17,31,0.06) !important;
}
.premium-proof-cards .proof-card-hero:hover{
  background:
    linear-gradient(180deg, rgba(255,255,255,0.98), rgba(255,255,255,0.85)),
    radial-gradient(circle at 20% 0%, rgba(37,99,235,0.10), transparent 40%) !important;
  box-shadow: 0 18px 40px rgba(7,17,31,0.10) !important;
}
.proof-card-hero small{
  color: #2563eb !important;
}
.proof-card-hero b{
  color: var(--gb-ink) !important;
}
.proof-card-hero span:not(.proof-icon){
  color: var(--gb-muted) !important;
}
.proof-icon{
  background: rgba(37,99,235,0.08) !important;
  border-color: rgba(37,99,235,0.12) !important;
  color: #2563eb !important;
}

/* Hero left tags style */
.hero-tags span{
  background: rgba(37, 99, 235, 0.06) !important;
  border: 1px solid rgba(37, 99, 235, 0.12) !important;
  color: #2563eb !important;
