/* Company brief: light premium section */
#about {
  background:
    radial-gradient(circle at 12% 18%, rgba(37, 99, 235, 0.08), transparent 42%),
    radial-gradient(circle at 88% 82%, rgba(22, 199, 132, 0.07), transparent 42%),
    linear-gradient(180deg, #ffffff, #f7f9fd) !important;
  color: var(--text) !important;
  position: relative;
  z-index: 1;
}
#about h2, #about h3, #about b, #about strong {
  color: var(--ink) !important;
}
#about p {
  color: var(--muted) !important;
}
#about .eyebrow {
  background: rgba(37, 99, 235, 0.08) !important;
  color: #2563eb !important;
  border: 1px solid rgba(37, 99, 235, 0.14) !important;
}
#about .about-left-col {
  display: flex;
  flex-direction: column;
}
#about .about-bpo-bottom .bpo-points {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 12px;
  margin-top: 0;
  padding: 22px;
  border-radius: 24px;
  background:
    radial-gradient(circle at 18% 12%, rgba(37, 99, 235, 0.2), transparent 42%),
    radial-gradient(circle at 88% 88%, rgba(22, 199, 132, 0.12), transparent 40%),
    linear-gradient(180deg, #0c1829, #07111f) !important;
  border: 1px solid rgba(255, 255, 255, 0.08) !important;
  box-shadow: 0 18px 40px rgba(7, 17, 31, 0.18) !important;
}
#about .about-bpo-bottom .bpo-point {
  background: rgba(255, 255, 255, 0.05) !important;
  border: 1px solid rgba(255, 255, 255, 0.1) !important;
  box-shadow: none !important;
  transition: transform 0.25s ease, background-color 0.25s ease, border-color 0.25s ease;
  padding: 16px;
  border-radius: 18px;
}
#about .about-bpo-bottom .bpo-point:hover {
  transform: translateY(-2px);
  background: rgba(255, 255, 255, 0.08) !important;
  border-color: rgba(37, 99, 235, 0.35) !important;
  box-shadow: 0 10px 24px rgba(37, 99, 235, 0.12) !important;
}
#about .about-bpo-bottom .bpo-point b {
  color: #ffffff !important;
  font-size: 15px !important;
  margin-bottom: 6px;
}
#about .about-bpo-bottom .bpo-point span {
  color: rgba(255, 255, 255, 0.72) !important;
  font-size: 13px !important;
  line-height: 1.5 !important;
}
#about .result-box {
  background: linear-gradient(135deg, rgba(22, 199, 132, 0.10), rgba(37, 99, 235, 0.08)) !important;
  border: 1px solid rgba(37, 99, 235, 0.14) !important;
  color: var(--muted) !important;
}
#about .result-box strong {
  color: var(--ink) !important;
}
#about .about-brief-shell {
  position: relative;
  overflow: hidden;
  background: #ffffff !important;
  border: 1px solid var(--line) !important;
  border-radius: 34px;
  padding: 34px 36px;
  box-shadow: 0 20px 50px rgba(7, 17, 31, 0.08) !important;
}
#about .about-brief-shell::before {
  content: "";
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 4px;
  background: linear-gradient(90deg, #16c784, #2563eb, #7c3aed);
}
#about .about-brief-header {
  padding-bottom: 22px;
  border-bottom: 1px solid var(--line);
}
#about .about-brief-header h2 {
  margin: 0 !important;
  font-size: clamp(30px, 3.4vw, 46px) !important;
  line-height: 1.08 !important;
  letter-spacing: -1px !important;
}
#about .about-brief-grid {
  display: grid;
  grid-template-columns: minmax(0, 1fr) minmax(0, 1.08fr);
  gap: 28px;
  margin-top: 24px;
  align-items: stretch;
}
#about .about-story p {
  margin: 0 0 16px !important;
  font-size: 18px !important;
  line-height: 1.75 !important;
}
#about .about-story p:last-child {
  margin-bottom: 0 !important;
}
#about .about-bpo-panel {
  height: 100%;
  display: flex;
  flex-direction: column;
}
#about .about-bpo-head {
  display: flex;
  flex-direction: column;
  gap: 0;
  align-items: stretch;
  padding: 0;
  border-radius: 24px;
  background: linear-gradient(135deg, #f8fafc, #f0f9ff) !important;
  border: 1px solid var(--line) !important;
  height: 100%;
  min-height: 0;
  overflow: hidden;
}
#about .about-bpo-logo {
  flex: 0 0 auto;
  width: 100%;
  aspect-ratio: 16 / 9;
  height: auto;
  border-radius: 0;
  overflow: hidden;
  background: #0d1b2f;
  display: block;
  padding: 0;
  border: none;
  border-bottom: 1px solid var(--line);
  box-shadow: none;
}
#about .about-bpo-logo img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  object-position: center;
  transform: scale(1.32);
  display: block;
}
#about .about-bpo-intro {
  flex: 1 1 auto;
  display: flex;
  flex-direction: column;
  justify-content: center;
  padding: 22px 26px 26px;
  min-height: 0;
}
#about .about-bpo-intro h3 {
  font-size: clamp(20px, 2.1vw, 26px) !important;
  line-height: 1.22 !important;
  margin: 8px 0 10px !important;
}
#about .about-bpo-intro p {
  margin: 0 !important;
  font-size: 15px !important;
  line-height: 1.65 !important;
}
#about .about-bpo-intro .eyebrow {
  margin-bottom: 8px !important;
}
#about .bpo-badge-inline {
  display: inline-flex;
  align-items: center;
  padding: 7px 12px;
  border-radius: 999px;
  background: #07111f !important;
  color: #ffffff !important;
  font-weight: 900;
  font-size: 11px;
  margin-bottom: 10px;
  border: 1px solid rgba(7, 17, 31, 0.12) !important;
}
#about .about-bpo-bottom {
  margin-top: 28px;
  display: flex;
  flex-direction: column;
  gap: 14px;
}
#about .about-bpo-bottom .result-box {
  margin-top: 0 !important;
}
@media (max-width: 1040px) {
  #about .about-brief-grid {
    grid-template-columns: 1fr;
  }
  #about .about-bpo-bottom .bpo-points {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
}
@media (max-width: 690px) {
  #about .about-brief-shell {
    padding: 24px 20px;
  }
  #about .about-bpo-intro {
    text-align: center;
    align-items: center;
    padding: 20px 18px 22px;
  }
  #about .about-bpo-logo img {
    transform: scale(1.28);
  }
  #about .about-bpo-bottom .bpo-points {
    grid-template-columns: 1fr;
    padding: 18px;
  }
}

/* Credentials — dark theme + full-width image gallery */
.credentials-dark {
  position: relative;
  overflow: hidden;
  background:
    radial-gradient(circle at 16% 0%, rgba(22, 199, 132, 0.18), transparent 30%),
    radial-gradient(circle at 88% 10%, rgba(37, 99, 235, 0.18), transparent 28%),
    linear-gradient(135deg, #07111f, #0d1b2f) !important;
  color: rgba(255, 255, 255, 0.82);
}
.credentials-dark:before {
  content: "";
  position: absolute;
  inset: 0;
  background-image:
    linear-gradient(rgba(255, 255, 255, 0.035) 1px, transparent 1px),
    linear-gradient(90deg, rgba(255, 255, 255, 0.035) 1px, transparent 1px);
  background-size: 44px 44px;
  pointer-events: none;
}
.credentials-dark .wrap {
  position: relative;
  z-index: 2;
}
.credentials-dark .eyebrow {
  background: rgba(255, 255, 255, 0.08) !important;
  color: #dbeafe !important;
  border: 1px solid rgba(255, 255, 255, 0.12) !important;
}
.credentials-dark .credentials-content {
  background: rgba(255, 255, 255, 0.05) !important;
  border: 1px solid rgba(255, 255, 255, 0.1) !important;
  box-shadow: none !important;
}
.credentials-dark .credentials-content h2 {
  color: #fff !important;
}
.credentials-dark .credentials-content p {
  color: rgba(255, 255, 255, 0.74) !important;
}
.credentials-dark .cred-item {
  background: rgba(255, 255, 255, 0.06) !important;
  border: 1px solid rgba(255, 255, 255, 0.1) !important;
}
.credentials-dark .cred-item h3 {
  color: #fff !important;
}
.credentials-dark .cred-item p {
  color: rgba(255, 255, 255, 0.68) !important;
}
.credentials-dark .cred-icon {
  background: rgba(37, 99, 235, 0.2) !important;
}
.credentials-dark .legal-note {
  background: rgba(255, 255, 255, 0.06) !important;
  border: 1px solid rgba(255, 255, 255, 0.1) !important;
  color: rgba(255, 255, 255, 0.7) !important;
}
.credentials-dark .legal-note strong {
  color: #fff !important;
}
.credentials-dark .credentials-gallery {
  margin-top: 28px;
  width: 100%;
}
.credentials-dark .media-collage-full {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 14px;
  width: 100%;
}
.credentials-dark .media-collage-full .media-card {
  position: relative;
  overflow: hidden;
  height: min(42vw, 360px);
  min-height: 260px;
  border-radius: 24px;
  background: #0a1424;
  border: 1px solid rgba(255, 255, 255, 0.1);
  box-shadow: 0 16px 40px rgba(0, 0, 0, 0.28);
}
.credentials-dark .media-collage-full .media-card img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  object-position: center;
  display: block;
}
.credentials-dark .media-label {
  background: rgba(7, 17, 31, 0.88) !important;
  color: #fff !important;
  border: 1px solid rgba(255, 255, 255, 0.1);
  backdrop-filter: blur(8px);
}
.credentials-dark .credentials-proof-strip {
  margin-top: 22px;
}
.credentials-dark .credentials-proof-strip .company-proof {
  background: rgba(255, 255, 255, 0.06) !important;
  border: 1px solid rgba(255, 255, 255, 0.1) !important;
  box-shadow: none !important;
}
.credentials-dark .credentials-proof-strip .company-proof b {
  color: #fff !important;
}
.credentials-dark .credentials-proof-strip .company-proof span {
  color: rgba(255, 255, 255, 0.68) !important;
}
@media (max-width: 1040px) {
  .credentials-dark .media-collage-full {
    grid-template-columns: 1fr 1fr;
  }
  .credentials-dark .media-collage-full .media-card:first-child {
    grid-column: span 2;
  }
}
@media (max-width: 690px) {
  .credentials-dark .media-collage-full {
    grid-template-columns: 1fr;
  }
  .credentials-dark .media-collage-full .media-card:first-child {
    grid-column: auto;
  }
  .credentials-dark .media-collage-full .media-card {
    height: 240px;
    min-height: 240px;
  }
}

/* Solution area: make it look like GrowBoostly growth operating system */
