/* ===== Complete Solution Areas — Premium service cards (no global .service-card conflict) ===== */
#solutions .about-solutions-grid{
  display:grid;
  grid-template-columns:repeat(3,minmax(0,1fr));
  gap:22px;
  align-items:stretch;
  margin-top:8px;
}
#solutions .about-svc-card{
  position:relative;
  display:flex;
  flex-direction:column;
  align-items:flex-start;
  padding:28px 26px 24px;
  border-radius:22px;
  background:#fff;
  border:1px solid rgba(231,235,243,.95);
  box-shadow:0 8px 32px rgba(7,17,31,.06);
  transition:transform .28s ease, box-shadow .28s ease, border-color .28s ease;
  overflow:hidden;
  min-height:100%;
}
#solutions .about-svc-card::before{
  content:"";
  position:absolute;
  top:0;
  left:0;
  right:0;
  height:4px;
  background:linear-gradient(90deg,#16c784,#2563eb,#7c3aed);
}
#solutions .about-svc-card:hover{
  transform:translateY(-5px);
  box-shadow:0 18px 44px rgba(7,17,31,.11);
  border-color:rgba(37,99,235,.18);
}
#solutions .about-svc-icon{
  width:52px;
  height:52px;
  border-radius:16px;
  display:grid;
  place-items:center;
  font-size:24px;
  line-height:1;
  margin-bottom:18px;
  flex-shrink:0;
  background:linear-gradient(145deg,rgba(22,199,132,.14),rgba(37,99,235,.10),rgba(124,58,237,.08));
  box-shadow:inset 0 1px 0 rgba(255,255,255,.85), 0 4px 14px rgba(37,99,235,.08);
}
#solutions .about-svc-card h3{
  margin:0 0 10px;
  font-size:19px;
  font-weight:800;
  line-height:1.28;
  letter-spacing:-.35px;
  color:#07111f;
}
#solutions .about-svc-card p{
  margin:0;
  font-size:14.5px;
  line-height:1.68;
  color:#667085;
  flex-grow:1;
}
#solutions .about-svc-list{
  width:100%;
  margin:18px 0 0;
  padding:16px 0 0;
  border-top:1px solid rgba(231,235,243,.9);
  list-style:none;
  display:flex;
  flex-direction:column;
  gap:10px;
}
#solutions .about-svc-list li{
  display:flex;
  align-items:flex-start;
  gap:10px;
  margin:0;
  padding:0;
  min-width:0;
  max-width:none;
  width:100%;
  height:auto;
  background:transparent;
  border-radius:0;
  position:static;
  transform:none;
  z-index:auto;
  font-size:13.5px;
  font-weight:600;
  line-height:1.45;
  color:#475467;
}
#solutions .about-svc-check{
  flex:0 0 22px;
  width:22px;
  height:22px;
  border-radius:50%;
  display:inline-grid;
  place-items:center;
  background:rgba(37,99,235,.1);
  color:#2563eb;
  font-size:11px;
  font-weight:900;
  line-height:1;
  margin-top:1px;
}
#solutions .about-svc-list li > span:last-child{
  flex:1;
  min-width:0;
}
#solutions .about-svc-card:nth-child(1){
  background:radial-gradient(circle at 100% 0%,rgba(22,199,132,.07),transparent 42%),#fff;
}
#solutions .about-svc-card:nth-child(2){
  background:radial-gradient(circle at 100% 0%,rgba(37,99,235,.08),transparent 42%),#fff;
}
#solutions .about-svc-card:nth-child(3){
  background:radial-gradient(circle at 100% 0%,rgba(124,58,237,.07),transparent 42%),#fff;
}
#solutions .about-svc-card:nth-child(4){
  background:radial-gradient(circle at 100% 0%,rgba(249,115,22,.06),transparent 42%),#fff;
}
#solutions .about-svc-card:nth-child(5){
  background:radial-gradient(circle at 100% 0%,rgba(16,185,129,.07),transparent 42%),#fff;
}
#solutions .about-svc-card:nth-child(6){
  background:radial-gradient(circle at 100% 0%,rgba(14,165,233,.08),transparent 42%),#fff;
}
@media(max-width:1040px){
  #solutions .about-solutions-grid{
    grid-template-columns:repeat(2,minmax(0,1fr));
    gap:18px;
  }
}
@media(max-width:690px){
  #solutions .about-solutions-grid{
    grid-template-columns:1fr;
