/* ===== Improved Trust Strip Section V9 ===== */
.premium-trust-strip{
  position:relative;
  z-index:5;
  margin-top:26px !important;
  padding:0 0 12px;
}
.trust-proof-layout{
  display:grid;
  grid-template-columns:.82fr 1.18fr;
  gap:18px;
  align-items:stretch;
  padding:18px;
  border-radius:38px;
  background:
    radial-gradient(circle at 0% 0%,rgba(22,199,132,.10),transparent 28%),
    radial-gradient(circle at 100% 0%,rgba(37,99,235,.10),transparent 30%),
    #ffffff;
  border:1px solid var(--gb-line);
  box-shadow:0 22px 60px rgba(7,17,31,.10);
}
.trust-proof-intro{
  position:relative;
  overflow:hidden;
  border-radius:30px;
  padding:30px;
  background:linear-gradient(135deg,#07111f,#0d1b2f);
  color:#fff;
  min-height:100%;
}
.trust-proof-intro:before{
  content:"";
  position:absolute;
  right:-85px;
  top:-85px;
  width:230px;
  height:230px;
  border-radius:50%;
  background:rgba(37,99,235,.22);
}
.trust-proof-intro:after{
  content:"";
  position:absolute;
  left:-70px;
  bottom:-90px;
  width:210px;
  height:210px;
  border-radius:50%;
  background:rgba(22,199,132,.16);
}
.trust-proof-intro > *{
  position:relative;
  z-index:2;
}
.trust-kicker{
  display:inline-flex;
  padding:8px 13px;
  border-radius:999px;
  background:rgba(255,255,255,.10);
  border:1px solid rgba(255,255,255,.14);
  color:#fff;
  font-weight:900;
  font-size:12px;
  margin-bottom:18px;
}
.trust-proof-intro h2{
  margin:0 0 12px;
  color:#fff;
  font-size:clamp(28px,3vw,42px);
  line-height:1.08;
  letter-spacing:-.8px;
}
.trust-proof-intro p{
