  font-size:15.5px;
  line-height:1.72;
}
.trust-proof-cards{
  display:grid;
  grid-template-columns:1fr 1fr;
  gap:14px;
}
.trust-proof-card{
  position:relative;
  overflow:hidden;
  display:grid;
  grid-template-columns:58px 1fr;
  gap:14px;
  align-items:flex-start;
  padding:20px;
  border-radius:26px;
  background:
    radial-gradient(circle at 100% 0%,rgba(37,99,235,.07),transparent 36%),
    linear-gradient(180deg,#fff,#fbfcff);
  border:1px solid rgba(231,235,243,.95);
  box-shadow:0 14px 34px rgba(7,17,31,.07);
  transition:.25s;
}
.trust-proof-card:hover{
  transform:translateY(-5px);
  box-shadow:0 24px 55px rgba(7,17,31,.13);
}
.trust-proof-card:before{
  content:"";
  position:absolute;
  inset:0 0 auto;
  height:5px;
  background:linear-gradient(90deg,#16c784,#2563eb,#7c3aed);
}
.trust-proof-icon{
  width:58px;
  height:58px;
  border-radius:21px;
  display:grid;
  place-items:center;
  font-size:25px;
  background:
    radial-gradient(circle at 30% 20%,rgba(255,255,255,.95),transparent 38%),
    linear-gradient(135deg,rgba(22,199,132,.16),rgba(37,99,235,.13),rgba(124,58,237,.12));
  box-shadow:0 12px 28px rgba(37,99,235,.12), inset 0 0 0 1px rgba(37,99,235,.10);
}
.trust-proof-card small{
