}
.trust-proof-card h3{
  margin:0 0 7px;
  color:#07111f;
  font-size:21px;
  line-height:1.18;
  letter-spacing:-.25px;
}
.trust-proof-card p{
  margin:0;
  color:#667085;
  font-size:14px;
