/* Industries grid (matching B2C page style) */
.b2c-industries{padding:60px 0}
.b2c-section-title{margin-bottom:36px}
.b2c-section-title h2{font-size:32px;font-weight:800;color:var(--ink)}
.b2c-industry-grid{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:18px;margin-top:18px}
.industry-card{display:block;border:1px solid #e6eefc;border-radius:12px;padding:26px 18px;text-align:center;background:#fff;transition:all .28s}
.industry-card .icon-wrap{font-size:36px;margin-bottom:12px;display:block}
.industry-card h6{font-size:15px;font-weight:800;margin:0;color:var(--ink)}
.industry-card p{margin:8px 0 0;color:var(--muted);font-size:14px}
.industry-card:hover{border-color:#2563eb;box-shadow:0 12px 36px rgba(37,99,235,.08);transform:translateY(-6px)}
@media(max-width:1040px){.b2c-industry-grid{grid-template-columns:repeat(2,1fr)}}
@media(max-width:690px){.b2c-industry-grid{grid-template-columns:1fr}}

/* FAQ accordion (CSS-only) */
.b2c-faq{padding:60px 0}
.b2c-faq .faq-grid{max-width:980px;margin:28px auto 0}
.faq-item{border:1px solid #e6eefc;border-radius:12px;margin-bottom:12px;overflow:hidden;background:#fff}
.faq-item summary{cursor:pointer;padding:18px 22px;font-weight:800;font-size:16px;list-style:none;outline:none;position:relative}
.faq-item summary::-webkit-details-marker{display:none}
.faq-item summary::after{content:'+';position:absolute;right:20px;top:18px;font-size:20px;color:#2563eb}
.faq-item[open] summary::after{content:'−'}
.faq-item[open] summary{background:#f0f7ff;color:#2563eb}
.faq-content{padding:16px 22px;background:#f8fbff;color:var(--muted);font-size:15px;line-height:1.7}
@media(max-width:690px){
  .trust-proof-layout{
